let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Meeting analysis is not valid JSON. Raw output: ' + raw);
}

return [
  {
    json: {
      transcript: $('Set Transcript Input').first().json.transcript,
      meeting_analysis: parsed
    }
  }
];

values.content:
=Transform the meeting analysis below into slide content following the schema and rules exactly.

OUTPUT RULES (non-negotiable):
- Return ONLY the JSON object. No markdown, no explanation, no ```json fences.
- Validate your output mentally before returning: check slide count, bullet counts, and row counts.
- Every bullet must be ≤ 18 words and start with a capital letter.
- Bullets must be declarative statements, not questions or vague phrases.
- Priorities must be exactly one of: "High" | "Medium" | "Low"
- due_date: use exact date from data (e.g. "2025-06-15") or "TBD" if not mentioned.
- owner: use the name/role mentioned in the data, or "TBD" if unspecified.

REQUIRED SCHEMA:
{
  "deck_title": "<string>",
  "slides": [
    {
      "slide_type": "title",
      "title": "<string>",
      "subtitle": "<string>"
    },
    {
      "slide_type": "executive_summary",
      "title": "Executive Summary",
      "bullets": ["<string>", "..."]  // 3 to 5 bullets
    },
    {
      "slide_type": "objectives",
      "title": "High-Level Objectives",
      "bullets": ["<string>", "<string>", "<string>"]  // exactly 3 bullets
    },
    {
      "slide_type": "action_items",
      "title": "Action Items",
      "table_rows": [  // exactly 3 rows
        {"task": "<string>", "owner": "<string>", "due_date": "<string>", "priority": "<High|Medium|Low>"},
        {"task": "<string>", "owner": "<string>", "due_date": "<string>", "priority": "<High|Medium|Low>"},
        {"task": "<string>", "owner": "<string>", "due_date": "<string>", "priority": "<High|Medium|Low>"}
      ]
    },
    {
      "slide_type": "next_steps",
      "title": "Next Steps",
      "bullets": ["<string>", "..."]  // 3 to 5 bullets
    }
  ]
}

SLIDE CONSTRAINTS SUMMARY:
| Slide              | Field        | Count     |
|--------------------|--------------|-----------|
| executive_summary  | bullets      | 3–5       |
| objectives         | bullets      | exactly 3 |
| action_items       | table_rows   | exactly 3 |
| next_steps         | bullets      | 3–5       |

Meeting analysis:
{{ JSON.stringify($json.meeting_analysis) }}

parameters.jsCode:
const raw =
  $json.output ||
  $json.text ||
  $json.response ||
  $json.content ||
  $json.message ||
  JSON.stringify($json);

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Deck content is not valid JSON. Raw output: ' + raw);
}

return [
  {
    json: {
      transcript: $('Set Transcript Input').first().json.transcript,
      meeting_analysis: $('Parse Meeting Analysis').first().json.meeting_analysis,
      deck_content: parsed
    }
  }
];

const raw =
  $json.output ??
  $json.text ??
  $json.response ??
  $json.content ??
  $json.message ??
  JSON.stringify($json);

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('QA output is not valid JSON. Raw output: ' + raw);
}

function getNodeJson(nodeName, fieldName) {
  try {
    return $(nodeName).first().json[fieldName];
  } catch (e) {
    throw new Error(`Could not read field "${fieldName}" from node "${nodeName}". Check that the node exists, has executed, and the name matches exactly. Original error: ${e.message}`);
  }
}

return [
  {
    json: {
      transcript: getNodeJson('Set Transcript Input', 'transcript'),
      meeting_analysis: getNodeJson('Parse Meeting Analysis', 'meeting_analysis'),
      deck_content: getNodeJson('Parse Deck Content', 'deck_content'),
      qa_result: parsed
    }
  }
];

const response = $json.deck_content;

if (!Array.isArray(response) || !response.length) {
  throw new Error('deck_content is missing or not an array');
}

const deck = response?.[0]?.content?.[0]?.text;

if (!deck || typeof deck !== 'object') {
  throw new Error('Deck payload not found at deck_content[0].content[0].text');
}

const slides = Array.isArray(deck.slides) ? deck.slides : [];

let out = `Deck Title: ${deck.deck_title || 'Untitled'}\n\n`;

for (const slide of slides) {
  out += `=== ${slide.title || 'Untitled Slide'} ===\n`;

  if (slide.subtitle) out += `${slide.subtitle}\n`;

  if (Array.isArray(slide.bullets)) {
    out += slide.bullets.map(b => `- ${b}`).join('\n') + '\n';
  }

  if (Array.isArray(slide.table_rows)) {
    for (const row of slide.table_rows) {
      out += `- Task: ${row.task || ''} | Owner: ${row.owner || ''} | Due: ${row.due_date || ''} | Priority: ${row.priority || ''}\n`;
    }
  }

  out += '\n';
}

return [{ json: { ...$json, deck_text: out, deck } }];

const slides =
  Array.isArray($json.deck?.slides) ? $json.deck.slides :
  Array.isArray($json.deck_content?.[0]?.content?.[0]?.text?.slides)
    ? $json.deck_content[0].content[0].text.slides
    : [];

const titleSlide = slides.find(s => s.slide_type === 'title') || {};
const execSlide = slides.find(s => s.slide_type === 'executive_summary') || {};
const objSlide = slides.find(s => s.slide_type === 'objectives') || {};
const actionSlide = slides.find(s => s.slide_type === 'action_items') || {};
const nextSlide = slides.find(s => s.slide_type === 'next_steps') || {};

const execBullets = Array.isArray(execSlide.bullets) ? execSlide.bullets : [];
const objectives = Array.isArray(objSlide.bullets) ? objSlide.bullets : [];
const actions = Array.isArray(actionSlide.table_rows) ? actionSlide.table_rows : [];
const nextSteps = Array.isArray(nextSlide.bullets) ? nextSlide.bullets : [];

return [{
  json: {
    ...$json,
    placeholders: {
      TITLE: titleSlide.title || '',
      SUBTITLE: titleSlide.subtitle || '',
      EXEC_BULLET_1: execBullets[0] || '',
      EXEC_BULLET_2: execBullets[1] || '',
      EXEC_BULLET_3: execBullets[2] || '',
      EXEC_BULLET_4: execBullets[3] || '',
      EXEC_BULLET_5: execBullets[4] || '',
      OBJ_1: objectives[0] || '',
      OBJ_2: objectives[1] || '',
      OBJ_3: objectives[2] || '',
      ACTION_1_TASK: actions[0]?.task || '',
      ACTION_1_OWNER: actions[0]?.owner || '',
      ACTION_1_DUE: actions[0]?.due_date || '',
      ACTION_1_PRIORITY: actions[0]?.priority || '',
      ACTION_2_TASK: actions[1]?.task || '',
      ACTION_2_OWNER: actions[1]?.owner || '',
      ACTION_2_DUE: actions[1]?.due_date || '',
      ACTION_2_PRIORITY: actions[1]?.priority || '',
      ACTION_3_TASK: actions[2]?.task || '',
      ACTION_3_OWNER: actions[2]?.owner || '',
      ACTION_3_DUE: actions[2]?.due_date || '',
      ACTION_3_PRIORITY: actions[2]?.priority || '',
      NEXT_1: nextSteps[0] || '',
      NEXT_2: nextSteps[1] || '',
      NEXT_3: nextSteps[2] || '',
      NEXT_4: nextSteps[3] || '',
      NEXT_5: nextSteps[4] || ''
    }
  }
}];
